remediation.samplePowerShell:
Get-StoragePool -CimSession $ClusterName | Where-Object HealthStatus -ne 'Healthy' | ForEach-Object {
    $_ | Get-VirtualDisk | Repair-VirtualDisk
}
Get-StorageJob -CimSession $ClusterName

# Resource Bridge deployment is driven from the Azure Local portal;
# verify post-deploy state:
Get-AzResource -ResourceGroupName $ResourceGroup -ResourceType 'Microsoft.ResourceConnector/appliances'

# Secured-Core is enabled via the Azure portal or OEM firmware tooling.
# Verify current state per node:
Invoke-Command -ComputerName $NodeName -ScriptBlock { Get-CimInstance Win32_DeviceGuard }

# Inspect expiring certificates on each node:
Invoke-Command -ComputerName (Get-ClusterNode -Cluster $ClusterName).Name -ScriptBlock {
    Get-ChildItem Cert:\LocalMachine -Recurse | Where-Object { $_.NotAfter -lt (Get-Date).AddDays(90) }
}

Invoke-Command -ComputerName $NodeName -ScriptBlock {
    Get-VM | Sort-Object CPUUsage -Descending | Select-Object -First 10 Name, State, CPUUsage, MemoryDemand
}

Get-Volume -CimSession $ClusterName | Where-Object DriveType -eq 'Fixed' | ForEach-Object {
    [PSCustomObject]@{ Name = $_.FileSystemLabel; UsedPct = [int](($_.Size - $_.SizeRemaining) / $_.Size * 100) }
}

Invoke-Command -ComputerName (Get-ClusterNode -Cluster $ClusterName).Name -ScriptBlock {
    Get-Service -Name HealthService, ClusSvc, himds | Select-Object MachineName, Name, Status, StartType
}
